package com.enterprise.banking.service;

import com.enterprise.banking.exception.BankingServiceException;
import com.enterprise.banking.model.*;
import com.enterprise.banking.security.SOAPMessageSignatureVerifier;

import javax.annotation.Resource;
import javax.jws.HandlerChain;
import javax.jws.WebService;
import javax.xml.ws.WebServiceContext;
import javax.xml.ws.handler.MessageContext;
import java.math.BigDecimal;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;
import java.util.logging.Level;
import java.util.logging.Logger;

@WebService(
    serviceName = "BankingWebService",
    portName = "BankingServicePort",
    endpointInterface = "com.enterprise.banking.service.BankingService",
    targetNamespace = "https://enterprise.banking.com/ws/banking",
    wsdlLocation = "WEB-INF/wsdl/BankingService.wsdl"
)
@HandlerChain(file = "handler-chain.xml")
public class BankingServiceImpl implements BankingService {

    private static final Logger LOGGER = Logger.getLogger(BankingServiceImpl.class.getName());

    @Resource
    private WebServiceContext webServiceContext;

    // Simulated account store
    private static final Map<String, BigDecimal> accountBalances = new ConcurrentHashMap<>();
    private static final Map<String, TransactionResponse> transactionHistory = new ConcurrentHashMap<>();

    static {
        accountBalances.put("ACC-001", new BigDecimal("50000.00"));
        accountBalances.put("ACC-002", new BigDecimal("75000.00"));
        accountBalances.put("ACC-003", new BigDecimal("120000.00"));
        accountBalances.put("ACC-004", new BigDecimal("30000.00"));
    }

    @Override
    public TransactionResponse processTransaction(BankTransaction transaction) throws BankingServiceException {
        LOGGER.info("Processing transaction: " + transaction.getTransactionId());

        validateSecurityContext();
        validateTransaction(transaction);

        try {
            switch (transaction.getTransactionType()) {
                case TRANSFER:
                    return executeTransfer(transaction);
                case DEPOSIT:
                    return executeDeposit(transaction);
                case WITHDRAWAL:
                    return executeWithdrawal(transaction);
                case PAYMENT:
                    return executePayment(transaction);
                case REFUND:
                    return executeRefund(transaction);
                default:
                    throw new BankingServiceException(
                        "Unsupported transaction type",
                        "INVALID_TYPE",
                        "Transaction type " + transaction.getTransactionType() + " is not supported"
                    );
            }
        } catch (BankingServiceException e) {
            throw e;
        } catch (Exception e) {
            LOGGER.log(Level.SEVERE, "Error processing transaction", e);
            throw new BankingServiceException(
                "Internal processing error",
                "PROCESSING_ERROR",
                e.getMessage(),
                e
            );
        }
    }

    @Override
    public AccountBalance getAccountBalance(String accountId) throws BankingServiceException {
        LOGGER.info("Retrieving balance for account: " + accountId);

        validateSecurityContext();

        BigDecimal balance = accountBalances.get(accountId);
        if (balance == null) {
            throw new BankingServiceException(
                "Account not found",
                "ACCOUNT_NOT_FOUND",
                "No account found with ID: " + accountId
            );
        }

        return new AccountBalance(accountId, balance, "USD");
    }

    @Override
    public TransactionResponse transferFunds(String sourceAccountId, String targetAccountId,
                                              BigDecimal amount, String currency) throws BankingServiceException {
        LOGGER.info("Transferring funds from " + sourceAccountId + " to " + targetAccountId);

        validateSecurityContext();

        BankTransaction transaction = new BankTransaction(
            generateTransactionId(),
            sourceAccountId,
            targetAccountId,
            amount,
            currency,
            TransactionType.TRANSFER
        );

        return processTransaction(transaction);
    }

    @Override
    public TransactionResponse getTransactionStatus(String transactionId) throws BankingServiceException {
        LOGGER.info("Checking status for transaction: " + transactionId);

        validateSecurityContext();

        TransactionResponse response = transactionHistory.get(transactionId);
        if (response == null) {
            throw new BankingServiceException(
                "Transaction not found",
                "TRANSACTION_NOT_FOUND",
                "No transaction found with ID: " + transactionId
            );
        }

        return response;
    }

    // ---- Private helper methods ----

    private void validateSecurityContext() throws BankingServiceException {
        if (webServiceContext != null) {
            MessageContext messageContext = webServiceContext.getMessageContext();
            Boolean signatureVerified = (Boolean) messageContext.get("ws.security.signature.verified");
            if (signatureVerified != null && !signatureVerified) {
                throw new BankingServiceException(
                    "Security validation failed",
                    "SECURITY_FAILURE",
                    "SOAP message signature verification failed"
                );
            }
        }
    }

    private void validateTransaction(BankTransaction transaction) throws BankingServiceException {
        if (transaction == null) {
            throw new BankingServiceException("Transaction cannot be null", "VALIDATION_ERROR", "Null transaction");
        }
        if (transaction.getAmount() == null || transaction.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            throw new BankingServiceException("Invalid amount", "VALIDATION_ERROR", "Amount must be positive");
        }
        if (transaction.getSourceAccountId() == null || transaction.getSourceAccountId().isEmpty()) {
            throw new BankingServiceException("Source account required", "VALIDATION_ERROR", "Source account ID is missing");
        }
        if (transaction.getAmount().compareTo(new BigDecimal("1000000")) > 0) {
            throw new BankingServiceException(
                "Amount exceeds maximum limit",
                "LIMIT_EXCEEDED",
                "Maximum transaction amount is 1,000,000"
            );
        }
    }

    private TransactionResponse executeTransfer(BankTransaction transaction) throws BankingServiceException {
        String sourceId = transaction.getSourceAccountId();
        String targetId = transaction.getTargetAccountId();
        BigDecimal amount = transaction.getAmount();

        BigDecimal sourceBalance = accountBalances.get(sourceId);
        if (sourceBalance == null) {
            throw new BankingServiceException("Source account not found", "ACCOUNT_NOT_FOUND", "Source: " + sourceId);
        }

        BigDecimal targetBalance = accountBalances.get(targetId);
        if (targetBalance == null) {
            throw new BankingServiceException("Target account not found", "ACCOUNT_NOT_FOUND", "Target: " + targetId);
        }

        if (sourceBalance.compareTo(amount) < 0) {
            return TransactionResponse.failure(transaction.getTransactionId(), "Insufficient funds", 400);
        }

        synchronized (accountBalances) {
            accountBalances.put(sourceId, sourceBalance.subtract(amount));
            accountBalances.put(targetId, targetBalance.add(amount));
        }

        String refNumber = "REF-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        TransactionResponse response = TransactionResponse.success(transaction.getTransactionId(), refNumber);
        transactionHistory.put(transaction.getTransactionId(), response);

        LOGGER.info("Transfer completed: " + refNumber);
        return response;
    }

    private TransactionResponse executeDeposit(BankTransaction transaction) throws BankingServiceException {
        String targetId = transaction.getTargetAccountId();
        BigDecimal amount = transaction.getAmount();

        BigDecimal targetBalance = accountBalances.get(targetId);
        if (targetBalance == null) {
            throw new BankingServiceException("Account not found", "ACCOUNT_NOT_FOUND", "Account: " + targetId);
        }

        accountBalances.put(targetId, targetBalance.add(amount));

        String refNumber = "DEP-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        TransactionResponse response = TransactionResponse.success(transaction.getTransactionId(), refNumber);
        transactionHistory.put(transaction.getTransactionId(), response);
        return response;
    }

    private TransactionResponse executeWithdrawal(BankTransaction transaction) throws BankingServiceException {
        String sourceId = transaction.getSourceAccountId();
        BigDecimal amount = transaction.getAmount();

        BigDecimal sourceBalance = accountBalances.get(sourceId);
        if (sourceBalance == null) {
            throw new BankingServiceException("Account not found", "ACCOUNT_NOT_FOUND", "Account: " + sourceId);
        }

        if (sourceBalance.compareTo(amount) < 0) {
            return TransactionResponse.failure(transaction.getTransactionId(), "Insufficient funds", 400);
        }

        accountBalances.put(sourceId, sourceBalance.subtract(amount));

        String refNumber = "WDR-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        TransactionResponse response = TransactionResponse.success(transaction.getTransactionId(), refNumber);
        transactionHistory.put(transaction.getTransactionId(), response);
        return response;
    }

    private TransactionResponse executePayment(BankTransaction transaction) throws BankingServiceException {
        return executeTransfer(transaction);
    }

    private TransactionResponse executeRefund(BankTransaction transaction) throws BankingServiceException {
        return executeDeposit(transaction);
    }

    private String generateTransactionId() {
        return "TXN-" + UUID.randomUUID().toString();
    }
}

